{
  "intent": "check_and_fix",
  "intent_description": "ICMP probes to server 172.16.0.12 are failing (0/25 replies). Restore IP connectivity so pings to 172.16.0.12 succeed by ensuring the LAN interface toward the server is up, routing to 172.16.0.0/24 exists on upstream routers, and ICMP is not denied by ACLs on the path.",
  "target": "172.16.0.12",
  "needs_fix": true,
  "plan": {
    "problem": "Server 172.16.0.12 returns 0/25 ICMP replies — likely causes: R2 LAN interface down or misconfigured, missing route to 172.16.0.0/24 on upstream routers, or ACLs blocking ICMP between routers.",
    "fix_summary": "1) Ensure R2 GigabitEthernet0/0/0 (LAN to 172.16.0.0/24) is up with IP 172.16.0.1/24. 2) Ensure R1 and R3 have a route to 172.16.0.0/24 via R2. 3) Remove any ICMP deny entries from ACLs named R1_TO_R2 and R2_TO_R1.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "set_interface_state",
        "target": "GigabitEthernet0/0/0",
        "parameters": [
          "up"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "set_interface_ip",
        "target": "GigabitEthernet0/0/0",
        "parameters": [
          "172.16.0.1/24"
        ]
      },
      {
        "id": 3,
        "device": "router1",
        "action": "add_static_route",
        "target": "172.16.0.0/24",
        "parameters": [
          "next-hop 10.0.0.2"
        ]
      },
      {
        "id": 4,
        "device": "router3",
        "action": "add_static_route",
        "target": "172.16.0.0/24",
        "parameters": [
          "next-hop 10.0.0.2"
        ]
      },
      {
        "id": 5,
        "device": "router1",
        "action": "remove_acl",
        "target": "R1_TO_R2",
        "parameters": [
          "deny icmp"
        ]
      },
      {
        "id": 6,
        "device": "router2",
        "action": "remove_acl",
        "target": "R2_TO_R1",
        "parameters": [
          "deny icmp"
        ]
      }
    ]
  }
}

